import React, { useState, useEffect, useRef } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';
import { pdfjs as pdfjsWorker } from 'pdfjs-dist';

pdfjs.GlobalWorkerOptions.workerSrc = 
  `//cdn.jsdelivr.net/npm/pdfjs-dist@5.4.296/legacy/build/pdf.worker.min.js`;
interface PDFViewerProps {
  fileUrl: string;
  onDocumentLoad?: (numPages: number) => void;
}

const PDFViewer: React.FC<PDFViewerProps> = ({ fileUrl, onDocumentLoad }) => {
  const [numPages, setNumPages] = useState<number | null>(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [scale, setScale] = useState(1.0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const isMounted = useRef(true);

  useEffect(() => {
    return () => { isMounted.current = false; };
  }, []);

  useEffect(() => {
    setLoading(true);
    setError(null);
    setPageNumber(1);
  }, [fileUrl]);

  const onDocumentSuccess = (pdf: any) => {
    if (!isMounted.current) return;
    setNumPages(pdf.numPages);
    setLoading(false);
    if (onDocumentLoad) onDocumentLoad(pdf.numPages);
  };

  const onDocumentError = (err: any) => {
    if (!isMounted.current) return;
    console.error('❌ Erreur PDF:', err);
    
    let message = '📄 Impossible de charger le PDF';
    if (err.name === 'InvalidPDFException') {
      message = '⚠️ Fichier PDF corrompu';
    } else if (err.status === 403) {
      message = '🔐 Bucket Supabase non public\nAllez dans Storage → document-files → Settings → Activez "Public"';
    } else if (err.status === 404) {
      message = '🔍 PDF introuvable (URL invalide)';
    }
    
    setError(`${message}\n\nDétails: ${err.message || 'Erreur inconnue'}`);
    setLoading(false);
  };

  const goToPrevPage = () => setPageNumber(prev => Math.max(prev - 1, 1));
  const goToNextPage = () => setPageNumber(prev => Math.min(prev + 1, numPages || 1));
  const zoomIn = () => setScale(prev => Math.min(prev + 0.2, 3.0));
  const zoomOut = () => setScale(prev => Math.max(prev - 0.2, 0.5));

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-800">
      {/* Barre d'outils */}
      <div className="flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-700/50">
        <div className="flex items-center gap-3">
          <button
            onClick={goToPrevPage}
            disabled={pageNumber <= 1 || loading}
            className={`p-1.5 rounded-md ${
              pageNumber <= 1 || loading
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
          >
            <i className="fas fa-chevron-left"></i>
          </button>
          
          <div className="flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-gray-300">
            <span>Page</span>
            <input
              type="number"
              value={pageNumber}
              onChange={(e) => {
                const page = parseInt(e.target.value);
                if (!isNaN(page) && page >= 1 && page <= (numPages || 1)) {
                  setPageNumber(page);
                }
              }}
              min="1"
              max={numPages || 1}
              disabled={loading}
              className="w-12 text-center px-1.5 py-0.5 border border-gray-300 dark:border-gray-600 rounded text-gray-900 dark:text-white disabled:bg-gray-100 disabled:dark:bg-gray-700"
            />
            <span>sur {numPages || '?'}</span>
          </div>
          
          <button
            onClick={goToNextPage}
            disabled={pageNumber >= (numPages || 1) || loading}
            className={`p-1.5 rounded-md ${
              pageNumber >= (numPages || 1) || loading
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
          >
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
        
        <div className="flex items-center gap-2">
          <button onClick={zoomOut} disabled={loading} className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md disabled:opacity-50">
            <i className="fas fa-search-minus"></i>
          </button>
          <span className="text-sm font-medium text-gray-700 dark:text-gray-300">{Math.round(scale * 100)}%</span>
          <button onClick={zoomIn} disabled={loading} className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md disabled:opacity-50">
            <i className="fas fa-search-plus"></i>
          </button>
        </div>
      </div>
      
      {/* Zone de visualisation */}
      <div className="flex-1 overflow-auto bg-white dark:bg-gray-800 flex items-center justify-center p-4 relative">
        {loading && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 dark:bg-gray-800/90 z-10">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-3"></div>
            <p className="text-gray-600 dark:text-gray-400">Chargement du PDF...</p>
          </div>
        )}
        
        {error && (
          <div className="absolute inset-0 flex items-center justify-center p-6 z-10">
            <div className="max-w-md bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 p-4 rounded-lg text-center">
              <i className="fas fa-exclamation-triangle text-3xl mb-2"></i>
              <p className="font-medium mb-2">Erreur de chargement</p>
              <p className="text-sm whitespace-pre-line mb-3">{error}</p>
              <button
                onClick={() => window.open(fileUrl, '_blank')}
                className="mt-2 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-md text-sm"
              >
                Ouvrir le PDF directement
              </button>
            </div>
          </div>
        )}
        
        <Document
          file={fileUrl}
          onLoadSuccess={onDocumentSuccess}
          onLoadError={onDocumentError}
          className="max-w-full"
        >
          <Page
            pageNumber={pageNumber}
            scale={scale}
            renderTextLayer={true}
            renderAnnotationLayer={true}
            className="shadow-lg rounded-lg"
          />
        </Document>
      </div>
      
      <div className="py-2 px-4 text-center text-xs text-gray-500 dark:text-gray-400 border-t border-gray-200 dark:border-gray-700">
        {loading ? 'Chargement...' : error ? 'Erreur' : numPages ? `✅ ${numPages} page${numPages > 1 ? 's' : ''}` : 'Prêt'}
      </div>
    </div>
  );
};

export default PDFViewer;
